const submit = async () => {
  try {
    const res = await fetch("http://localhost:5000/register", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify(form)
    });

    const text = await res.text();
    console.log("RAW:", text);

    const result = JSON.parse(text);

    if (res.status !== 200) {
      alert(result.message);
      return;
    }

    alert(result.message);

  } catch (err) {
    console.error(err);
    alert("Error");
  }
};
